    async fn on_created(&self, event: WorkflowStepCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = WorkflowStepProjection::new(
            event.id,
            event.workflow_id,
            event.step_number,
            event.step_type,
            event.step_name,
            event.description,
            event.status,
            event.parameters,
            event.result,
            event.started_at,
            event.completed_at,
            event.failed_at,
            event.duration_ms,
            event.error_message,
            event.retry_count,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: WorkflowStepUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.workflow_id = event.workflow_id;
            projection.step_number = event.step_number;
            projection.step_type = event.step_type;
            projection.step_name = event.step_name;
            projection.description = event.description;
            projection.status = event.status;
            projection.parameters = event.parameters;
            projection.result = event.result;
            projection.started_at = event.started_at;
            projection.completed_at = event.completed_at;
            projection.failed_at = event.failed_at;
            projection.duration_ms = event.duration_ms;
            projection.error_message = event.error_message;
            projection.retry_count = event.retry_count;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: WorkflowStepDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
